#!/usr/bin/env python3
"""Tiny webhook -> Telegram notify bridge."""
from flask import Flask, request
import requests
import os

app = Flask(__name__)
TOKEN = os.environ.get("NOTIFY_TOKEN", "")
CHAT_ID = os.environ.get("NOTIFY_CHAT_ID", "")

def send_tg(msg):
    """Send a message via Telegram bot."""
    if not TOKEN or not CHAT_ID:
        print("Missing NOTIFY_TOKEN or NOTIFY_CHAT_ID")
        return
    url = f"https://api.telegram.org/bot{TOKEN}/sendMessage"
    try:
        r = requests.post(url, json={"chat_id": CHAT_ID, "text": msg}, timeout=10)
        r.raise_for_status()
    except Exception as e:
        print(f"Telegram send failed: {e}")

@app.route("/hook", methods=["POST"])
def hook():
    data = request.get_json(silent=True)
    if not data or "payload" not in data:
        return {"ok": False, "error": "missing payload"}, 400
    payload = data["payload"]
    send_tg(f"[hook] {payload}")
    return {"ok": True}

@app.route("/health")
def health():
    return {"status": "ok"}

if __name__ == "__main__":
    port = int(os.environ.get("PORT", 5000))
    app.run(host="0.0.0.0", port=port)

